    "cases.cost_risk_and_contingency.step.report.out.tornado": "Diagram tornado",
    "cases.cost_risk_and_contingency.step.report.title": "Tetapkan kontinjensi dan laporkan",
    "cases.cost_risk_and_contingency.step.report.what": "Pilih tingkat keyakinan yang sesuai dengan pekerjaan, baca kontinjensi yang tersirat pada titik itu di kurva-S, dan ekspor diagram tornado yang mengurutkan pendorong terbesar dari sebaran risiko.",
    "cases.cost_risk_and_contingency.step.report.why": "Kontinjensi yang diambil dari distribusi lebih meyakinkan di hadapan dewan direksi atau klien dibanding angka rata sepuluh persen. Diagram tornado menunjukkan persis untuk risiko apa dana itu disisihkan, sehingga angkanya terlihat beralasan, bukan mengada-ada.",
    "cases.cost_risk_and_contingency.step.simulate.in.ranges": "Rentang tiga titik",
    "cases.cost_risk_and_contingency.step.simulate.in.uncertain": "Baris tidak pasti",
    "cases.cost_risk_and_contingency.step.simulate.out.curve": "Kurva P50 hingga P90",
    "cases.cost_risk_and_contingency.step.simulate.out.distribution": "Distribusi biaya",
    "cases.cost_risk_and_contingency.step.simulate.title": "Jalankan simulasi Monte Carlo",
    "cases.cost_risk_and_contingency.step.simulate.what": "Berikan setiap baris tidak pasti nilai rendah, paling mungkin dan tinggi, hubungkan baris-baris yang bergerak bersamaan seperti bahan bakar dan angkutan, lalu jalankan simulasi ribuan iterasi untuk membentuk distribusi biaya.",
    "cases.cost_risk_and_contingency.step.simulate.why": "Satu angka utama saja menyembunyikan seberapa besar hasil akhir bisa bergeser. Kurva P50 hingga P90 menunjukkan dengan jelas berapa banyak cadangan yang perlu dibawa untuk mencapai tingkat keyakinan yang siap Anda pertanggungjawabkan.",
    "cases.cost_risk_and_contingency.title": "Tetapkan kontinjensi dari risiko biaya",
    "cases.cost_value_reconciliation.desc": "Bandingkan biaya yang telah dikomit dengan nilai yang telah diperoleh pada tanggal cut-off yang sama, dan baca margin sebenarnya setiap periode selagi masih ada waktu untuk bertindak.",
    "cases.cost_value_reconciliation.step.cost.in.commitments": "Pesanan yang telah diterbitkan",
    "cases.cost_value_reconciliation.step.cost.in.payments": "Pembayaran yang telah disertifikasi",
    "cases.cost_value_reconciliation.step.cost.out.accruals": "Akrual sudah termasuk",
