    "cases.earned_value_and_forecast.step.update.out.percent": "Persentase penyelesaian ditetapkan",
    "cases.earned_value_and_forecast.step.update.title": "Perbarui jadwal",
    "cases.earned_value_and_forecast.step.update.what": "Majukan setiap aktivitas hingga tanggal data, tetapkan persentase penyelesaian yang jujur untuk yang sedang berjalan, dan pastikan biaya terkomit dan aktual periode itu sudah dibukukan.",
    "cases.earned_value_and_forecast.step.update.why": "Earned value mewarisi setiap klaim kemajuan yang terlalu optimis yang Anda masukkan. Cut-off yang disiplin, tanpa pekerjaan yang dihitung sebelum benar-benar selesai, adalah satu-satunya hal yang membuat indeksnya layak dibaca.",
    "cases.earned_value_and_forecast.title": "Earned value dan perkiraan",
    "cases.elemental_cost_plan_and_classification.desc": "Susun rencana biaya berdasarkan elemen yang diklasifikasikan alih-alih berdasarkan trade, periksa terhadap aturan klasifikasi, dan terbitkan rencana yang benar-benar bisa digunakan perancang.",
    "cases.elemental_cost_plan_and_classification.step.classify.in.plan": "Rencana terstruktur elemen",
    "cases.elemental_cost_plan_and_classification.step.classify.in.rules": "Set aturan klasifikasi",
    "cases.elemental_cost_plan_and_classification.step.classify.out.clean": "Rencana yang terklasifikasi penuh",
    "cases.elemental_cost_plan_and_classification.step.classify.out.report": "Laporan pemeriksaan struktur",
    "cases.elemental_cost_plan_and_classification.step.classify.title": "Periksa aturan klasifikasi",
    "cases.elemental_cost_plan_and_classification.step.classify.what": "Jalankan aturan struktur pada rencana dan pastikan setiap bagian membawa kode klasifikasi yang diminta standar, tanpa ada yang tersisa dalam kategori tidak terklasifikasi.",
    "cases.elemental_cost_plan_and_classification.step.classify.why": "Rencana biaya yang tidak bisa dipetakan secara bersih ke standar klasifikasi tidak bisa dibandingkan dengan benchmark atau diserahkan ke quantity surveyor di pihak lain.",
    "cases.elemental_cost_plan_and_classification.step.issue.in.plan": "Rencana biaya tervalidasi",
    "cases.elemental_cost_plan_and_classification.step.issue.in.totals": "Total biaya elemen",
    "cases.elemental_cost_plan_and_classification.step.issue.out.budget": "Anggaran siap desain",
    "cases.elemental_cost_plan_and_classification.step.issue.out.report": "Laporan biaya elemen",
    "cases.elemental_cost_plan_and_classification.step.issue.title": "Terbitkan laporan elemen",
    "cases.elemental_cost_plan_and_classification.step.issue.what": "Ekspor rencana biaya yang diuraikan per elemen lengkap dengan kode klasifikasinya, siap digunakan tim desain dan disetujui klien.",
    "cases.elemental_cost_plan_and_classification.step.issue.why": "Laporan elemen adalah satu-satunya dokumen yang memungkinkan perancang melihat persis di mana posisi anggaran dan di mana keputusan desain akan menggesernya.",
    "cases.elemental_cost_plan_and_classification.step.structure.in.design": "Desain skema",
