    "cases.manage_the_plant_and_equipment_register.step.maintenance.out.flags": "Tanda servis jatuh tempo",
    "cases.manage_the_plant_and_equipment_register.step.maintenance.title": "Tandai inspeksi dan servis",
    "cases.manage_the_plant_and_equipment_register.step.maintenance.what": "Tandai mesin yang mendekati jadwal inspeksi wajib atau servis berdasarkan jam dan tanggal penggunaannya.",
    "cases.manage_the_plant_and_equipment_register.step.maintenance.why": "Alat angkat yang belum diinspeksi atau mesin yang lewat jadwal servis adalah risiko penghentian kerja dan keselamatan. Menandainya lebih awal menjaga alat berat tetap legal dan berjalan.",
    "cases.manage_the_plant_and_equipment_register.step.register.in.hired": "Kontrak sewa",
