    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.out.closed": "Tindakan ditutup sebelum pekerjaan dimulai",
    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.title": "Tindak lanjuti setiap tindakan",
    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.what": "Jika briefing mengungkap kontrol yang hilang, alat yang rusak atau kekurangan peralatan, angkat sebagai tindakan dengan penanggung jawab dan tanggal, lalu pastikan ditutup sebelum aktivitas berjalan.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.follow-up.why": "Briefing yang mengungkap bahaya lalu tidak ditindaklanjuti lebih buruk daripada tidak ada briefing sama sekali, karena risikonya kini sudah diketahui namun tidak dikelola. Menindaklanjuti tindakan itulah yang benar-benar menjaga keselamatan kru.",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.in.hazards": "Bahaya lokasi yang diketahui",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.in.plan": "Rencana kerja harian",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.activity": "Aktivitas berisiko tinggi terpilih",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.hazard": "Bahaya utama teridentifikasi",
