    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.out.controls": "Daftar kontrol & APD",
    "cases.run_a_toolbox_talk_and_record_attendance.step.prepare.out.talk": "Poin briefing yang disiapkan",
