    "cases.tender_from_boq.step.distribute.out.invites": "Undangan terkirim",
    "cases.tender_from_boq.step.distribute.out.status": "Status pengiriman",
    "cases.tender_from_boq.step.distribute.title": "Undang subkontraktor",
    "cases.tender_from_boq.step.distribute.what": "Susun daftar undangan dari direktori subkontraktor Anda atau ketik perusahaan secara manual, lalu kirimkan. Setiap penerima terbaca sebagai terkirim, tertunda atau gagal, sehingga tidak ada undangan yang diam-diam hilang.",
    "cases.tender_from_boq.step.distribute.why": "Lapangan peserta tender yang lebih luas dan berkualifikasi adalah yang mempertajam harga. Menerbitkan dari satu daftar juga meninggalkan audit yang bersih tentang siapa yang diundang dan kapan, yang penting jika pemberian kontrak pernah dipertanyakan.",
    "cases.tender_from_boq.step.package.in.boq": "BOQ sumber",
    "cases.tender_from_boq.step.package.in.deadline": "Batas waktu pengajuan",
    "cases.tender_from_boq.step.package.out.package": "Paket tender",
    "cases.tender_from_boq.step.package.out.schedule": "Jadwal pemberian harga peserta",
    "cases.tender_from_boq.step.package.title": "Buat paket tender",
    "cases.tender_from_boq.step.package.what": "Di Tendering, mulai paket baru, tetapkan BOQ ini sebagai sumbernya dan tentukan batas waktu pengajuan. Paket ini membawa posisi dan kuantitas yang berharga untuk ditawar perusahaan.",
    "cases.tender_from_boq.step.package.why": "Paket adalah yang membuat estimasi internal bisa diterbitkan. Membangunnya dari BOQ menjaga lingkup, kuantitas dan angka anggaran Anda tetap terjahit ke estimasi yang sudah Anda percayai.",
    "cases.tender_from_boq.title": "Jalankan tender dari BOQ",
    "cases.toolbox_talk_and_safety.desc": "Beri briefing kru tentang bahaya yang benar-benar dihadapi shift ini, catat siapa yang hadir, lalu buktikan lewat inspeksi lapangan bahwa kontrol yang disepakati benar-benar terpasang.",
    "cases.toolbox_talk_and_safety.step.brief.in.crew": "Kru pada shift",
    "cases.toolbox_talk_and_safety.step.brief.in.plan": "Rencana kerja shift",
    "cases.toolbox_talk_and_safety.step.brief.in.rams": "Penilaian risiko & metode",
    "cases.toolbox_talk_and_safety.step.brief.out.attendance": "Catatan kehadiran yang ditandatangani",
    "cases.toolbox_talk_and_safety.step.brief.out.briefed": "Kru yang telah dibriefing",
    "cases.toolbox_talk_and_safety.step.brief.title": "Jalankan toolbox talk",
    "cases.toolbox_talk_and_safety.step.brief.what": "Bahas bahaya spesifik untuk shift yang akan datang, metode kerja yang aman dan kontrol yang ada, lalu catat kehadiran sehingga setiap pekerja di lapangan tercatat menandatangani briefing.",
    "cases.toolbox_talk_and_safety.step.brief.why": "Kru yang sudah mendengar risikonya membuat keputusan yang lebih baik saat perancah terlihat tidak beres. Kehadiran yang ditandatangani juga menjadi catatan yang menunjukkan briefing benar-benar terjadi jika suatu insiden pernah diselidiki.",
    "cases.toolbox_talk_and_safety.step.verify.in.checklist": "Checklist keselamatan",
    "cases.toolbox_talk_and_safety.step.verify.in.controls": "Kontrol yang dibriefingkan",
    "cases.toolbox_talk_and_safety.step.verify.in.permits": "Izin kerja aktif",
    "cases.toolbox_talk_and_safety.step.verify.out.defects": "Kekurangan keselamatan tercatat",
    "cases.toolbox_talk_and_safety.step.verify.out.verified": "Kontrol terverifikasi",
    "cases.toolbox_talk_and_safety.step.verify.title": "Verifikasi kontrol saat inspeksi lapangan",
    "cases.toolbox_talk_and_safety.step.verify.what": "Inspeksi area kerja terhadap checklist, konfirmasikan pagar pengaman, akses, zona larangan dan izin kerja sesuai dengan yang dibriefingkan, dan catat setiap item yang kurang dengan foto.",
    "cases.toolbox_talk_and_safety.step.verify.why": "Toolbox talk hanya sebatas niat sampai inspeksi lapangan membuktikan pagar pengaman terpasang dan izin kerja aktif. Memeriksa kontrol di lapangan adalah yang mengubah kata-kata menjadi perlindungan yang benar-benar berlaku.",
    "cases.toolbox_talk_and_safety.title": "Toolbox talk dan pemeriksaan keselamatan",
    "cases.track_a_design_change_to_site_record.desc": "Lacak perubahan desain mulai dari gambar yang membawanya, melalui instruksi lokasi, hingga catatan yang membuktikan versi yang benar memang telah dibangun.",
