    "cases.track_a_design_change_to_site_record.step.revise.title": "Terbitkan gambar revisi",
    "cases.track_a_design_change_to_site_record.step.revise.what": "Daftarkan gambar revisi yang membawa perubahan desain, tandai versi sebelumnya sebagai usang dan catat dengan jelas apa yang berubah dan mengapa.",
    "cases.track_a_design_change_to_site_record.step.revise.why": "Perubahan yang hanya ada sebagai instruksi lisan di lokasi tidak memiliki jejak dokumen jika biaya atau waktu pernah dipertanyakan.",
    "cases.track_a_design_change_to_site_record.step.verify.in.drawing": "Gambar revisi",
