    "cases.track_an_opportunity_from_enquiry_to_tender.desc": "Catat kontak klien, jalankan peluang melalui pipeline, ubah kemenangan menjadi proyek dan bawa hingga ke tender.",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.contact.in.details": "Detail klien",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.contact.in.enquiry": "Pertanyaan masuk",
