    "cases.track_an_opportunity_from_enquiry_to_tender.step.tender.what": "Pindahkan peluang yang dimenangkan ke tendering untuk menyusun, memberi harga dan mengajukan penawaran.",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.tender.why": "Benang komersial harus mengalir tanpa putus dari pertanyaan pertama hingga harga yang diajukan. Kesenjangan adalah tempat lingkup dan margin bocor keluar.",
    "cases.track_an_opportunity_from_enquiry_to_tender.title": "Lacak peluang dari pertanyaan hingga tender",
    "cases.turn_field_time_into_payroll_and_labour_cost.desc": "Ambil jam kerja yang disetujui dari lokasi, jalankan melalui payroll dengan grade dan tarif yang benar, dan bukukan biaya tenaga kerja ke pekerjaan sehingga laporan biaya menunjukkan biaya sebenarnya dari pekerjaan tersebut.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.in.approval": "Persetujuan supervisor",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.in.timesheets": "Timesheet lapangan",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.out.codes": "Jam kerja per kode biaya",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.out.hours": "Jam kerja yang disetujui",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.title": "Kumpulkan timesheet yang disetujui",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.what": "Ambil timesheet mingguan dari lapangan, yang sudah diperiksa dan disetujui supervisor, dengan jam kerja dibukukan per pekerja dan terhadap kode biaya yang benar.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.why": "Payroll yang dijalankan dari jam kerja yang tidak disetujui membayar waktu yang tidak ditandatangani siapa pun. Timesheet yang disetujui adalah satu-satunya sumber bersih yang menjadi dasar upah dan biaya pekerjaan.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.in.codes": "Kode biaya",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.in.total": "Total payroll",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.out.costtodate": "Biaya hingga saat ini diperbarui",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.out.posted": "Biaya tenaga kerja dibukukan",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.title": "Bukukan biaya tenaga kerja ke pekerjaan",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.what": "Bukukan total payroll ke buku besar proyek terhadap kode biaya yang benar, sehingga pengeluaran tenaga kerja duduk bersama material, alat berat dan subkontrak.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.why": "Laporan biaya yang tidak memasukkan tenaga kerja memberi tahu bahwa pekerjaan lebih murah dari sebenarnya. Membukukan tagihan upah ke pekerjaan adalah yang membuat biaya hingga saat ini lengkap dan margin jujur.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.run.in.hours": "Jam kerja yang disetujui",
