    "finance.confirm_pay_msg_immutable": "Tindakan ini mencatat pembayaran sebagai entri buku besar yang tidak dapat diubah dan menutup faktur. Tindakan ini tidak dapat dibatalkan.",
    "finance.invoice_sent_for_approval": "Faktur dikirim untuk persetujuan",
    "finance.send_for_approval": "Kirim untuk persetujuan",
    "finance.send_for_approval_failed": "Gagal mengirim faktur untuk persetujuan",
    "finance.send_for_approval_hint": "Pindahkan faktur draf ini ke status tertunda agar manajer dapat menyetujuinya.",
    "finance.status_current": "saat ini",
    "finance.status_edit_hint": "Pindahkan faktur antara status draf, tertunda, dan dibatalkan. Menyetujui faktur dan menandainya sebagai dibayar dilakukan dari tombol Setujui dan Tandai Dibayar pada baris faktur.",
    "finance.status_label": "Status",
    "geo_hub.empty.no_anchor_description_v2": "Tambatkan secara otomatis dari alamat yang Anda atur di pengaturan proyek, atau pilih koordinat secara manual. Anda dapat menyempurnakannya dengan menyeret setelah pin ditempatkan.",
    "geo_hub.empty.no_anchor_description_v3": "Tambatkan secara otomatis dari alamat yang Anda atur di pengaturan proyek, atau tempatkan pin langsung di peta. Anda dapat menyempurnakannya dengan menyeret setelah pin ditempatkan.",
    "geo_hub.empty.place_manually_cta": "Tempatkan pin di peta",
    "geo_hub.place_anchor.instruction": "Klik peta untuk menempatkan proyek ini",
    "geo_hub.place_anchor.locating": "Menentukan lokasi proyek ini dari alamatnya...",
