    "modules.dev_step_copy": "Buat scaffold dari template",
    "modules.dev_step_manifest": "Edit manifest",
    "modules.dev_step_models": "Tambah model & skema (opsional)",
    "modules.dev_step_restart": "Restart dan aktifkan",
    "modules.dev_step_router": "Tambah router",
